package globals

// AnyAuthenticatedUserId is the ID of the user that represents any authenticated user in Boundary.
const AnyAuthenticatedUserId = "any"

// RecoveryUserId is the ID of the recovery user in Boundary.
const RecoveryUserId = "recovery"

